#!/usr/bin/env bash
# workflow-5.sh — 读者数据运营与救书（网文独有的即时反馈闭环） SOP walkthrough for 网文写作.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="网文写作"
WORKFLOW="读者数据运营与救书（网文独有的即时反馈闭环）"

usage() {
  cat <<EOF
workflow-5.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-5.sh             # interactive
  ./workflow-5.sh --dry-run
  ./workflow-5.sh --json
  ./workflow-5.sh --explain
  ./workflow-5.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "读者数据运营与救书（网文独有的即时反馈闭环）" 工作流。

一句话: 从「上架/上推后追读完读数据异常」到「诊断扑街原因→改大纲/换爽点/加节奏救书 or 及时止损弃书重开」——**这是网文与影视编剧差异最尖锐的工序**：影视交付后无法改，网文每天拿数据、每章可调，数据反馈直接重写后续剧情。

入门 SOP 共 4 步, 失败模式自检 4 项。

相关心智模型:
  • 黄金三章定生死：为留人而非为铺垫写开局: 网文开局不是慢热铺垫，是前三章/万字内必须抛出金手指 + 制造冲突 + 埋钩子 + 建立代入，否则签约率与追读直接塌——「最惨/最爽不过三章」。
  • 爽点是可理性设计的工程对象，不是灵感: 愤怒的香蕉「一开始是欲望，到后来是情绪，最后变成需求」——爽点能被作者主动观察、拆解、设计，心理描写可把爽感挖到极致，而非等灵感降临。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**读看板**：盯追读率（起点新书生死线）、完读率（番茄停推线）、均订/订阅、章评。 (evidence: [T03-S007, T03-S010])"
  "**定位扑点**：从章评+追读掉点定位「哪一章/哪个情节让读者弃书」——读者不适即是扑街信号。 (evidence: [T03-S005])"
  "**救书三招**：改后续大纲（转向读者要的方向）/ 换爽点（补强爽感、加打脸/金手指升级）/ 加节奏（提速、删水、前置高潮）。 (evidence: [T03-S002, T04-S002])"
  "**止损判断**：若救书无效且数据持续探底，及时完本/太监止损，把精力投新书（新书才有新推荐位）。 (evidence: [T03-S010])"
)
declare -a FAILURE_MODES=(
  "**闷头码字不看后台**：不盯追读/完读，等被停推才知道扑了 → 数据驱动是网文工艺核心，每天看看板。"
  "**被个别差评带偏乱改**：因几条差评推翻大方向 → 区分噪音 vs 结构性扑点，只改后者。"
  "**死磕扑街书不止损**：在没数据的书上耗几个月 → 救书无效就完本，新书有新推荐位。"
  "**救书只加更不改内容**：以为多更就能救，实则爽点/节奏问题没解决 → 救书要动大纲/爽点/节奏，不是堆字数。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-5-walkthrough"
fi
